firmware_template.source:
#include "espnow_broadcast.h"
#include <WiFi.h>
#include <esp_now.h>
static espnow_bc_cb _cb=nullptr;
static uint8_t broadcastAddr[]={0xFF,0xFF,0xFF,0xFF,0xFF,0xFF};
void _onRecv(const esp_now_recv_info_t*info,const uint8_t*data,int len){if(_cb)_cb(data,len);}
void espnow_bc_setup(){WiFi.mode(WIFI_STA);esp_now_init();esp_now_register_recv_cb(_onRecv);esp_now_peer_info_t pi={};memcpy(pi.peer_addr,broadcastAddr,6);pi.channel=0;pi.encrypt=false;esp_now_add_peer(&pi);Serial.println("[espnow_bc] OK");}
bool espnow_bc_send(const uint8_t*d,uint8_t l){return esp_now_send(broadcastAddr,d,l)==ESP_OK;}
void espnow_bc_on_receive(espnow_bc_cb cb){_cb=cb;}
